import type {
  FunctionComponent,
  KeyboardEvent,
  MouseEvent,
  ReactElement,
  ReactNode,
} from 'react';
import type { PopperProps } from '@andes/popper';
import type { ListGroupProps, ListItemProps } from '@andes/list';
import type { WithRef } from '@andes/common';

type DropdownItem = Pick<
  ListItemProps,
  'description' | 'disabled' | 'rightContent' | 'value'
> & {
  primary?: string;
  title?: string;
  type?: 'form' | 'native' | 'standalone';
};

type SearchConfig = {
  defaultValue?: string;
  filterCondition?: (
    searchText?: string,
    value?: string,
    dropdownItem?: ReactElement<DropdownItem>,
  ) => boolean;
  onChange?: (value: string) => void;
  placeholder?: string;
};

type FloatingMenuSpecificProps = WithRef<HTMLDivElement> & {
  /**
   * Whether the floating menu should allow unselect the current selected option. This is not valid for `multiple`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   * @default false
   */
  allowUnselect?: boolean;

  /**
   * Custom content to be used as the bottom slot of the floating menu.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   */
  bottomContent?: ReactNode;

  /**
   * Custom content, should be a collection or a mix of `<FloatingMenuGroup>` and `<FloatingMenuItem>`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   */
  children: Array<ReactElement> | ReactElement;

  /**
   * Add custom class.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   */
  className?: string;

  /**
   * Whether the floating menu should be open or not by default (uncontrolled mode).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   * @default false
   */
  defaultOpen?: boolean;

  /**
   * Default selected value for floating menu (uncontrolled mode).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   */
  defaultValue?: Array<string> | string;

  /**
   * Accessible label for the menu dialog.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   */
  dialogSrLabel?: string;

  /**
   * Component ID.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   */
  id?: string;

  /**
   * Floating menu max height.  It can be used for large options amount.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   */
  menuMaxHeight?: number;

  /**
   * Allows a multiple selection menu (not valid for `type="menu"`).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   * @default false
   */
  multiple?: boolean;

  /**
   * Callback executed when an option is selected. When `multiple` is on, values will be an array.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   */
  onChange?: (
    event: KeyboardEvent | MouseEvent,
    value?: Array<string> | string,
  ) => void;

  /**
   * Callback executed when the floating menu is closed.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   */
  onClose?: () => void;

  /**
   * Callback executed when the floating menu is open.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   */
  onOpen?: (event: KeyboardEvent | MouseEvent) => void;

  /**
   * Whether the floating menu should be open or not (controlled mode).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   */
  open?: boolean;

  /**
   * Position of the menu relative to the trigger.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   * @default 'bottom'
   */
  placement?: PopperProps['placement'];

  /**
   * Flag that enables/disables the search of floating menu options (not valid for `type="menu"`).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   * @default false
   */
  search?: SearchConfig | boolean;

  /**
   * Label for screen readers.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   */
  srLabel: string;

  /**
   * Custom content to be used as the top slot of the floating menu.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   */
  topContent?: ReactNode;

  /**
   * Custom content. Element that triggers the action to open and close the menu. Should be a `<button>`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   */
  trigger: ReactElement;

  /**
   * Defines what type of floating menu should be rendered.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   * @default 'menu'
   */
  type?: 'menu' | 'select';

  /**
   * Current selected value for floating menu (controlled mode).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   */
  value?: Array<string> | string;

  /**
   * Width in px (number) or in percentage (string) the menu has.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#props | Documentation}
   * @default 280
   */
  width?: number | string;
};

type FloatingMenuItemSpecificProps = {
  /**
   * Whether the item should be disabled.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#floatingmenuitem-extends-listitem-api | Documentation}
   * @default false
   */
  disabled?: boolean;

  /**
   * Text to display as item title.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#floatingmenuitem-extends-listitem-api | Documentation}
   */
  title?: string;

  /**
   * The value of the item that will be passed when selected.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#floatingmenuitem-extends-listitem-api | Documentation}
   */
  value: string;
};

type FloatingMenuGroupSpecificProps = {
  /**
   * Custom content. Should be one or a collection of `<FloatingMenuItem>`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#floatingmenugroup-extends-listgroup-api | Documentation}
   */
  children?: Array<ReactElement> | ReactElement;
};

export type FloatingMenuProps = FloatingMenuSpecificProps & {
  popperOptions?: PopperProps['popperOptions'];
};

export type FloatingMenuItemProps = FloatingMenuItemSpecificProps &
  Omit<ListItemProps, 'title'>;

type FloatingMenuGroupProps = FloatingMenuGroupSpecificProps & ListGroupProps;

/**
 * Floating Menu is essentially a card that contains lists with actionable or selectable rows which overlaps or
 * "floats above" the content of an UI.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu | Documentation}
 * @see {@link https://andes.adminml.com/#/components/floating-menu | UI Specs}
 * @example
 * import { FloatingMenu, FloatingMenuItem } from '@andes/floating-menu';
 *
 * const MyComponent = () => (
 *   <FloatingMenu id="example-with-html-button" onChange={onChangeHandler} trigger={<button>Trigger</button>}>
 *     <FloatingMenuItem value="1" title="Item 1" />
 *     <FloatingMenuItem value="2" title="Item 2" />
 *     <FloatingMenuItem value="3" title="Item 3" />
 *   </FloatingMenu>
 * );
 */
export const FloatingMenu: FunctionComponent<FloatingMenuProps>;

/**
 * FloatingMenu Item.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#floatingmenuitem-extends-listitem-api | Documentation}
 * @see {@link https://andes.adminml.com/#/components/floating-menu | UI Specs}
 * @example
 * import { FloatingMenu, FloatingMenuItem } from '@andes/floating-menu';
 *
 * const MyComponent = () => (
 *   <FloatingMenu id="example-with-html-button" onChange={onChangeHandler} trigger={<button>Trigger</button>}>
 *     <FloatingMenuItem value="1" title="Item 1" />
 *     <FloatingMenuItem value="2" title="Item 2" />
 *     <FloatingMenuItem value="3" title="Item 3" />
 *   </FloatingMenu>
 * );
 */
export const FloatingMenuItem: FunctionComponent<FloatingMenuItemProps>;

/**
 * FloatingMenu Group.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/floating-menu#floatingmenugroup-extends-listgroup-api | Documentation}
 * @see {@link https://andes.adminml.com/#/components/floating-menu | UI Specs}
 * @example
 * import { FloatingMenu, FloatingMenuItem, FloatingMenuGroup } from '@andes/floating-menu';
 *
 * const MyComponent = () => (
 *   <FloatingMenu id="example-with-html-button" onChange={onChangeHandler} trigger={<button>Trigger</button>}>
 *     <FloatingMenuGroup label="Tarjetas de crédito">
 *       <FloatingMenuItem value="visa" title="Visa" />
 *       <FloatingMenuItem value="mastercard" title="Mastercard" />
 *       <FloatingMenuItem value="amex" title="American Express" />
 *     </FloatingMenuGroup>
 *     <FloatingMenuGroup label="Efectivo en redes de pago">
 *       <FloatingMenuItem value="rapipado" title="RapiPago" />
 *       <FloatingMenuItem value="pagofacil" title="PagoFacil" />
 *     </FloatingMenuGroup>
 *   </FloatingMenu>
 * );
 */
export const FloatingMenuGroup: FunctionComponent<FloatingMenuGroupProps>;

export type DropdownItemProps = DropdownItem;

export type SearchConfigProps = SearchConfig;
